      await new Promise(r => setTimeout(r, 1000)); // \u6A21\u62DF\u5F02\u6B65\u767B\u5F55\n      alert(`\u767B\u5F55\u6210\u529F\uFF0C\u6B22\u8FCE ${form.username}`);\n    } finally {\n      setSubmitting(false);\n    }\n  };\n\n  return (\n    <form onSubmit={handleSubmit} noValidate>\n      <div>\n        <label>\u7528\u6237\u540D</label>\n        <input\n          name=\"username\"\n          value={form.username}\n          onChange={handleChange}\n          aria-invalid={!!errors.username}\n        />\n        {errors.username && <span style={{ color: 'red' }}>{errors.username}</span>}\n      </div>\n      <div>\n        <label>\u5BC6\u7801</label>\n        <input\n          type=\"password\"\n          name=\"password\"\n          value={form.password}\n          onChange={handleChange}\n        />\n        {errors.password && <span style={{ color: 'red' }}>{errors.password}</span>}\n      </div>\n      <button type=\"submit\" disabled={submitting}>\n        {submitting ? '\u767B\u5F55\u4E2D...' : '\u767B\u5F55'}\n      </button>\n    </form>\n  );\n}\n"})}),"\n",(0,o.jsx)(e.h3,{id:"\u53D7\u63A7-vs-\u975E\u53D7\u63A7\u9009\u578B\u901F\u67E5",children:"\u53D7\u63A7 vs \u975E\u53D7\u63A7\u9009\u578B\u901F\u67E5"}),"\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n\n",(0,o.jsxs)(e.table,{children:[(0,o.jsx)(e.thead,{children:(0,o.jsxs)(e.tr,{children:[(0,o.jsx)(e.th,{style:{textAlign:"left"},children:"\u573A\u666F"}),(0,o.jsx)(e.th,{style:{textAlign:"left"},children:"\u63A8\u8350\u65B9\u5F0F"})]})}),(0,o.jsxs)(e.tbody,{children:[(0,o.jsxs)(e.tr,{children:[(0,o.jsx)(e.td,{style:{textAlign:"left"},children:"\u5373\u65F6\u6821\u9A8C\u3001\u52A8\u6001\u8054\u52A8\uFF08\u7701\u5E02\u8054\u52A8\uFF09"}),(0,o.jsx)(e.td,{style:{textAlign:"left"},children:"\u53D7\u63A7\u7EC4\u4EF6"})]}),(0,o.jsxs)(e.tr,{children:[(0,o.jsx)(e.td,{style:{textAlign:"left"},children:"\u4EC5\u5728\u63D0\u4EA4\u65F6\u8BFB\u53D6\u4E00\u6B21\u503C"}),(0,o.jsxs)(e.td,{style:{textAlign:"l